class Solution:
    def minimumSteps(self, s: str) -> int:
        left = 0
        right = len(s) - 1
        steps = 0
        while left < right:
            if s[left] == '1':
                left += 1
            elif s[right] == '0':
                right -= 1
            else:
                while left < right and s[left] == '1':
                    left += 1
                while left < right and s[right] == '0':
                    right -= 1
                steps += 1
        return steps

